import{_ as s,c as a,o as n,a as l}from"./app.6cebd806.js";const e="/yubi-blog/assets/四层架构.a678befe.png",o="/yubi-blog/assets/六边形架构.42c438be.jpg",F=JSON.parse('{"title":"DDD的四层架构","description":"","frontmatter":{},"headers":[{"level":2,"title":"先看看后端大佬的理解","slug":"先看看后端大佬的理解","link":"#先看看后端大佬的理解","children":[]},{"level":2,"title":"在前端中四层架构","slug":"在前端中四层架构","link":"#在前端中四层架构","children":[]},{"level":2,"title":"领域模型 domain","slug":"领域模型-domain","link":"#领域模型-domain","children":[{"level":3,"title":"实体与值对象","slug":"实体与值对象","link":"#实体与值对象","children":[]},{"level":3,"title":"聚合","slug":"聚合","link":"#聚合","children":[]},{"level":3,"title":"限界上下文","slug":"限界上下文","link":"#限界上下文","children":[]}]}],"relativePath":"docs/设计模式相关/领域驱动设计_DDD/初步接触.md","lastUpdated":1677180519000}'),t={name:"docs/设计模式相关/领域驱动设计_DDD/初步接触.md"},p=l('<h1 id="ddd的四层架构" tabindex="-1">DDD的四层架构 <a class="header-anchor" href="#ddd的四层架构" aria-hidden="true">#</a></h1><h2 id="先看看后端大佬的理解" tabindex="-1">先看看后端大佬的理解 <a class="header-anchor" href="#先看看后端大佬的理解" aria-hidden="true">#</a></h2><ul><li>User Interface：用户界面层/展示层，负责与用户交互。包含显示信息、解释用户命令等；</li><li>Application：应用层，用来协调用户与各应用以及各应用之间的交互。不包含业务逻辑、不保存业务对象的状态；</li><li>Domain：领域层/模型层，负责表达业务概念，业务状态信息以及业务规则。包含领域模型、领域信息、业务对象的状态。领域层是业务软件的核心；</li><li>Infrastructure：基础设施层，为其他各层提供技术能力。包括为应用层传递消息、为领域层提供持久化机制、为用户界面层绘制屏幕组件等等。基础设施层还能够通过架构框架来支持四个层次间的交互模式。</li></ul><p><img src="'+e+`" alt=""></p><h2 id="在前端中四层架构" tabindex="-1">在前端中四层架构 <a class="header-anchor" href="#在前端中四层架构" aria-hidden="true">#</a></h2><pre><code>参考了后端MVC与DDD四层架构的区别，并且推到到前端。（MVVM是数据驱动的）
</code></pre><ul><li>梳理了一下 <ul><li>User Interface：用户界面层/展示层，负责与用户交互。（前端里应该就是视图层叭，例如template或者jsx部分。）</li><li>Application：应用层。应用之间的链接部分，使用各种领域和模型。<strong>*（感觉可以叫胶水层？连接领域和视图层）</strong></li><li>Domain：领域层/模型层，负责表达业务概念，业务状态信息以及业务规则。<strong>*（核心业务层）</strong></li><li>Infrastructure：基础设施层，为其他各层提供技术能力。（封装https，utils之类的杂活）</li></ul></li></ul><blockquote><p>这里让我想到了Function-based API提案解决的问题，<a href="https://v3.cn.vuejs.org/guide/composition-api-introduction.html#%E4%BB%80%E4%B9%88%E6%98%AF%E7%BB%84%E5%90%88%E5%BC%8F-api" target="_blank" rel="noreferrer">文档</a></p></blockquote><h1 id="六边形架构" tabindex="-1">六边形架构 <a class="header-anchor" href="#六边形架构" aria-hidden="true">#</a></h1><p><img src="`+o+`" alt=""></p><blockquote><p>在我看来，六边形架构更像是四层架构的一种详细介绍，虽然这个图是后端的，但是对前端依然有着巨大的参考价值。</p></blockquote><h2 id="领域模型-domain" tabindex="-1">领域模型 domain <a class="header-anchor" href="#领域模型-domain" aria-hidden="true">#</a></h2><blockquote><p>DDD全称为Domain Driven Design，领域驱动设计。理所当然，领域domain就是在DDD建模方法中最重要的东西。</p></blockquote><p>六边形架构中，领域模型包括：<strong>聚合，实体，值对象</strong>，领域事件，工厂，领域服务，资源层，防腐层。这里先看前三个。</p><h3 id="实体与值对象" tabindex="-1">实体与值对象 <a class="header-anchor" href="#实体与值对象" aria-hidden="true">#</a></h3><ul><li><strong>实体</strong>：当一个对象由其标识区分，这种对象称为实体（Entity）。（不可重复）</li><li><strong>值对象</strong>：当一个对象用于对事务进行描述而没有唯一标识时，被称为值对象（Value Object, VO）。具有不变性、相等性和可替换性。</li></ul><p>例如： 我们每个工作日都需要乘坐交通工具去上班。</p><p>在这个例子中：</p><ul><li>“我们”具有唯一标识（身份证），是实体。</li></ul><div class="language-ts"><button title="Copy Code" class="copy"></button><span class="lang">ts</span><pre class="shiki"><code><span class="line"><span style="color:#C792EA;">interface</span><span style="color:#A6ACCD;"> </span><span style="color:#FFCB6B;">IPeople</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">{</span></span>
<span class="line"><span style="color:#A6ACCD;">  </span><span style="color:#F07178;">id</span><span style="color:#89DDFF;">:</span><span style="color:#A6ACCD;"> </span><span style="color:#FFCB6B;">string</span><span style="color:#89DDFF;">;</span><span style="color:#A6ACCD;"> </span><span style="color:#676E95;">// 唯一标识</span></span>
<span class="line"><span style="color:#A6ACCD;">  </span><span style="color:#F07178;">name</span><span style="color:#89DDFF;">:</span><span style="color:#A6ACCD;"> </span><span style="color:#FFCB6B;">string</span><span style="color:#89DDFF;">;</span></span>
<span class="line"><span style="color:#89DDFF;">}</span></span>
<span class="line"></span></code></pre></div><ul><li>“乘坐公共交通”，是值对象。包含的信息可以是什么时候乘坐了什么类型的交通工具</li></ul><div class="language-ts"><button title="Copy Code" class="copy"></button><span class="lang">ts</span><pre class="shiki"><code><span class="line"><span style="color:#C792EA;">interface</span><span style="color:#A6ACCD;"> </span><span style="color:#FFCB6B;">ICommuterInfo</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">{</span></span>
<span class="line"><span style="color:#A6ACCD;">  </span><span style="color:#F07178;">type</span><span style="color:#89DDFF;">:</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">&#39;</span><span style="color:#C3E88D;">car</span><span style="color:#89DDFF;">&#39;</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">|</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">&#39;</span><span style="color:#C3E88D;">subway</span><span style="color:#89DDFF;">&#39;</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">|</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">&#39;</span><span style="color:#C3E88D;">other</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">;</span></span>
<span class="line"><span style="color:#A6ACCD;">  </span><span style="color:#F07178;">time</span><span style="color:#89DDFF;">:</span><span style="color:#A6ACCD;"> </span><span style="color:#FFCB6B;">Date</span><span style="color:#89DDFF;">;</span></span>
<span class="line"><span style="color:#89DDFF;">}</span></span>
<span class="line"></span></code></pre></div><blockquote></blockquote><ul><li>谨慎使用值对象 <ul><li>很多领域对象看起来符合值对象的概念，但是在具体业务中，我们需要给其加上唯一标识。</li></ul></li></ul><div class="language-txt"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki"><code><span class="line"><span style="color:#A6ACCD;">用户分组 UserGroup，如果需要唯一标识就是实体，不然就是VO。</span></span>
<span class="line"><span style="color:#A6ACCD;"></span></span>
<span class="line"><span style="color:#A6ACCD;">看起来，可以套用统计学意义上的事件集合来判断需不需要唯一标识。</span></span>
<span class="line"><span style="color:#A6ACCD;"></span></span></code></pre></div><h3 id="聚合" tabindex="-1">聚合 <a class="header-anchor" href="#聚合" aria-hidden="true">#</a></h3><ul><li><strong>聚合</strong>：Aggregate，是一组相关对象的集合。由根实体，值对象和实体组成。</li><li><strong>聚合根</strong>：是这个聚合的根节点。</li></ul><h3 id="限界上下文" tabindex="-1">限界上下文 <a class="header-anchor" href="#限界上下文" aria-hidden="true">#</a></h3><ul><li><strong>限界上下文</strong>: 一个由显示边界限定的特定职责。领域模型便存在于这个边界之内。在边界内，每一个模型概念，包括它的属性和操作，都具有特殊的含义。实体，值对象，聚合，聚合根都是限界上下文内部的元素。</li></ul><blockquote><p>感觉一个限界上下文可以理解为一个模块。划分限界上下文和划分模块差不多的感觉。</p></blockquote><p>挺多人推荐的美团团队技术文章中，对抽奖上下文的划分。</p><p><img src="https://awps-assets.meituan.net/mit-x/blog-images-bundle-2017/725d9171.svg" alt=""></p><h1 id="参考资料" tabindex="-1">参考资料 <a class="header-anchor" href="#参考资料" aria-hidden="true">#</a></h1><p><a href="https://tech.meituan.com/2017/12/22/ddd-in-practice.html" target="_blank" rel="noreferrer">https://tech.meituan.com/2017/12/22/ddd-in-practice.html</a><a href="https://www.cnblogs.com/duanxz/p/9922170.html" target="_blank" rel="noreferrer">https://www.cnblogs.com/duanxz/p/9922170.html</a></p><p><a href="https://mp.weixin.qq.com/s/3oa6pDQVrxKWI7IrN5ZKRQ" target="_blank" rel="noreferrer">https://mp.weixin.qq.com/s/3oa6pDQVrxKWI7IrN5ZKRQ</a></p>`,35),r=[p];function i(c,d,D,h,u,y){return n(),a("div",null,r)}const g=s(t,[["render",i]]);export{F as __pageData,g as default};
